// ═══════════════════════════════════════════════════════
// COMPONENTS
// ═══════════════════════════════════════════════════════

// BottomSheet is now re-exported from @wishlist/ui as `Sheet`
// (see import above: `Sheet as BottomSheet`). The iOS-touch behavior
// (drag-to-dismiss / velocity inertia / keyboard blur / text-field
// gesture bypass) was absorbed into the primitive 2026-04-20. See
// `docs/design-system/DESIGN_DECISIONS.md#2026-04-20--sheet-primitive-absorbs-bottomsheet-ios-touch-behavior-promoted-to-canonical`.

function ItemThumb({ item }: { item: Item | GuestItem }) {
  const [imgErr, setImgErr] = useState(false);
  // v2.1: 50×50 r=14 with linear accent-soft gradient (was 52×52 r=12 flat).
  // Source: docs/design-system/mockups/approved/v2.1-refresh-all-screens.html (.wb-wish-thumb)
  const baseStyle: React.CSSProperties = {
    width: 50,
    height: 50,
    borderRadius: 14,
    flexShrink: 0,
  };
  if (item.imageUrl && !imgErr) {
    return (
      <img
        src={item.imageUrl}
        alt=""
        onError={() => setImgErr(true)}
        style={{
          ...baseStyle,
          objectFit: 'cover',
          background: 'var(--wb-accent-soft)',
        }}
      />
    );
  }
  return (
    <div style={{
      ...baseStyle,
      background: 'linear-gradient(135deg, var(--wb-accent-soft-strong), var(--wb-accent-soft))',
      display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24,
      boxShadow: 'inset 0 1px 0 rgba(255,255,255,0.06)',
    }}>
      {getEmoji(item.title)}
    </div>
  );
}

function WishCardOwner({ item, onTap, onDelete, onComplete, locale, sourceLabel }: {
  item: Item;
  onTap: (item: Item) => void;
  onDelete: (item: Item) => void;
  onComplete?: (item: Item) => void;
  locale: Locale;
  sourceLabel?: string;
}) {
  const isPurchased = item.status === 'purchased';
  const isReserved = item.status === 'reserved';
  return (
    <Card
      variant="interactive"
      onClick={() => onTap(item)}
      style={{
        display: 'flex', gap: 14, alignItems: 'flex-start',
        // Match v2-wish-state-matrix .faint = opacity 0.55 (owner purchased).
        opacity: isPurchased ? 0.55 : 1,
        WebkitTapHighlightColor: 'transparent',
      }}
    >
      <ItemThumb item={item} />
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{
            fontSize: 15, fontWeight: 600, fontFamily: font,
            color: isPurchased ? 'var(--wb-text-muted)' : 'var(--wb-text)',
            textDecoration: isPurchased ? 'line-through' : 'none',
            lineHeight: 1.3, paddingRight: 8,
            letterSpacing: '-0.015em',
            display: 'inline-flex', flexWrap: 'wrap', alignItems: 'center', gap: 6,
          }}>
            <span>{item.title}</span>
            {(item.placementCount ?? 1) > 1 && (
              <Chip tone="accent" size="sm">
                🔗 {locale === 'ru' ? 'В ' : 'In '}{item.placementCount}
              </Chip>
            )}
          </div>
          <Chip tone={item.priority === 3 ? 'danger' : item.priority === 2 ? 'warning' : 'surface'} size="sm">
            {prioEmoji(item.priority)}
          </Chip>
        </div>
        {item.price != null && (
          <div style={{
            fontSize: 13, fontWeight: 650, marginTop: 2,
            color: 'var(--wb-text-secondary)',
            fontFamily: font,
            fontFeatureSettings: '"tnum"',
            textDecoration: isPurchased ? 'line-through' : 'none',
          }}>
            {fmtPrice(item.price, locale, item.currency ?? 'RUB')}
          </div>
        )}
        <div style={{ marginTop: 8, display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
          {item.url && <Chip tone="surface" size="sm">{t('link_label', locale)}</Chip>}
          {isReserved && <Chip tone="accent" size="md">{t('status_someone_reserved', locale)}</Chip>}
          {isPurchased && <Chip tone="success" size="md">{t('status_gifted', locale)}</Chip>}
        </div>
        {sourceLabel && (
          <div style={{ marginTop: 6 }}>
            <span style={{
              display: 'inline-block', fontSize: 10, fontWeight: 600,
              color: 'var(--wb-text-muted)',
              background: 'var(--wb-surface)',
              border: '1px solid var(--wb-border)',
              padding: '2px 9px', borderRadius: 100,
              letterSpacing: '0.1px',
            }}>
              {sourceLabel}
            </span>
          </div>
        )}
      </div>
    </Card>
  );
}

function WishCardGuest({ item, onTap, onReserve, onUnreserve, myActorHash, locale, secretByMe }: { item: GuestItem; onTap: (item: GuestItem) => void; onReserve: (item: GuestItem) => void; onUnreserve: (item: GuestItem) => void; myActorHash: string; locale: Locale; secretByMe?: boolean }) {
  const isPurchased = item.status === 'purchased';
  const isReserved = item.status === 'reserved';
  const isReservedByMe = isReserved && !!myActorHash && item.reservedByActorHash === myActorHash;
  // v2.1 wish-row state tints — reserved-by-me success-tint, purchased dim+strike.
  // Source: .wb-wish.reserved-by-me / .wb-wish.done in v2.1 mockup.
  const stateBg = isReservedByMe
    ? 'linear-gradient(135deg, var(--wb-card), rgba(74,222,128,0.09))'
    : undefined;
  const stateBorder = isReservedByMe ? '1px solid rgba(74,222,128,0.28)' : undefined;
  return (
    <Card
      variant="interactive"
      onClick={() => onTap(item)}
      style={{
        display: 'flex', gap: 14, alignItems: 'flex-start',
        opacity: isPurchased ? 0.45 : 1,
        background: stateBg,
        border: stateBorder,
        WebkitTapHighlightColor: 'transparent',
      }}
    >
      <ItemThumb item={item} />
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
          <div style={{
            fontSize: 15,
            fontWeight: 600,
            fontFamily: font,
            color: 'var(--wb-text)',
            lineHeight: 1.3,
            letterSpacing: '-0.015em',
            textDecoration: isPurchased ? 'line-through' : 'none',
            flex: 1, minWidth: 0,
          }}>
            {item.title}
          </div>
          <Chip tone={item.priority === 3 ? 'danger' : item.priority === 2 ? 'warning' : 'surface'} size="sm">
            {prioEmoji(item.priority)}
          </Chip>
        </div>
        {item.price != null && (
          <div style={{
            fontSize: 13,
            fontWeight: 650,
            marginTop: 2,
            color: 'var(--wb-text-secondary)',
            fontFamily: font,
            fontFeatureSettings: '"tnum"',
            textDecoration: isPurchased ? 'line-through' : 'none',
          }}>
            {fmtPrice(item.price, locale, item.currency ?? 'RUB')}
          </div>
        )}
        <div style={{
          marginTop: 8,
          display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap',
          fontSize: 11, color: 'var(--wb-text-muted)',
        }}>
          {item.url && (
            <a href={item.url} target="_blank" rel="noreferrer" onClick={(e) => e.stopPropagation()} style={{ textDecoration: 'none' }}>
              <Chip tone="accent" size="sm">{t('link_label', locale)}</Chip>
            </a>
          )}
          {item.status === 'available' && !secretByMe && (
            <Button variant="primary" size="sm" fullWidth={false} onClick={(e) => { e.stopPropagation(); onReserve(item); }}>{t('reserve_btn', locale)}</Button>
          )}
          {secretByMe && (
            <Chip tone="accent" size="md">{t('sr_card_chip_secret', locale)}</Chip>
          )}
          {isReservedByMe && (
            <>
              <Chip tone="success" size="md">{t('reserved_by_me', locale)}</Chip>
              <button onClick={(e) => { e.stopPropagation(); onUnreserve(item); }} style={{ background: 'none', border: 'none', padding: '4px 6px', fontSize: 11, color: 'var(--wb-text-muted)', cursor: 'pointer', fontFamily: font }}>{t('cancel', locale)}</button>
            </>
          )}
          {isReserved && !isReservedByMe && (
            <Chip tone="surface" size="md">{t('already_reserved', locale)}</Chip>
          )}
          {isPurchased && <Chip tone="success" size="md">{t('status_gifted', locale)}</Chip>}
        </div>
      </div>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════
// CARD REDESIGN — canary-only components
// ═══════════════════════════════════════════════════════

function resolveCardMode(itemCount: number, cardDisplayMode: string | undefined, isPro: boolean): 'compact' | 'showcase' {
  if (isPro && cardDisplayMode === 'showcase') return 'showcase';
  if (isPro && cardDisplayMode === 'compact') return 'compact';
  return itemCount <= 5 ? 'showcase' : 'compact';
}

function WishCardCompact({ item, onTap, locale, sourceLabel, isGuest, onReserve, onUnreserve, myActorHash, secretByMe }: {
  item: Item | GuestItem;
  onTap: (item: any) => void;
  locale: Locale;
  sourceLabel?: string;
  isGuest?: boolean;
  onReserve?: (item: any) => void;
  onUnreserve?: (item: any) => void;
  myActorHash?: string;
  secretByMe?: boolean;
}) {
  const [imgErr, setImgErr] = useState(false);
  const isPurchased = item.status === 'purchased';
  const isReserved = item.status === 'reserved';
  const isReservedByMe = isGuest && isReserved && !!(myActorHash) && (item as GuestItem).reservedByActorHash === myActorHash;
  const hasImg = !!item.imageUrl && !imgErr;
  const prioGrad = PRIO_GRADIENT[item.priority] ?? PRIO_GRADIENT[1];

  return (
    <div
      onClick={() => onTap(item)}
      className="wb-card-pressed"
      style={{
        borderRadius: 18, overflow: 'hidden',
        border: '1px solid var(--wb-border)',
        background: 'var(--wb-card)',
        display: 'flex', position: 'relative',
        minHeight: 88, opacity: isPurchased ? 0.45 : 1,
        cursor: 'pointer', WebkitTapHighlightColor: 'transparent',
        WebkitBackdropFilter: 'blur(14px)' as never,
        backdropFilter: 'blur(14px)' as never,
        transition: 'all 0.15s cubic-bezier(0.4, 0, 0.2, 1)',
      }}
    >
      {/* v2.1 top priority strip — accent gradient with glow */}
      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 2, background: prioGrad, opacity: 0.7, boxShadow: '0 0 8px var(--wb-accent-shadow-soft)' }} />

      {/* Left panel — image or emoji */}
      {hasImg ? (
        <div style={{ width: 88, flexShrink: 0, position: 'relative', overflow: 'hidden', maxHeight: 110 }}>
          <img
            src={item.imageUrl!}
            alt=""
            onError={() => setImgErr(true)}
            style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block', minHeight: 88, maxHeight: 110 }}
          />
          <div style={{
            position: 'absolute', bottom: 6, left: 6,
            width: 22, height: 22, borderRadius: '50%',
            background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(8px) saturate(140%)', WebkitBackdropFilter: 'blur(8px) saturate(140%)' as never,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 12, border: '1px solid rgba(255,255,255,0.12)',
          }}>
            {PRIO_EMOJI[item.priority] ?? '🙂'}
          </div>
        </div>
      ) : (
        <div style={{
          width: 88, flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 36,
          background: 'linear-gradient(135deg, var(--wb-accent-soft-strong), var(--wb-accent-soft))',
          minHeight: 88, position: 'relative',
          boxShadow: 'inset 0 1px 0 rgba(255,255,255,0.06)',
        }}>
          <span style={{ filter: 'drop-shadow(0 4px 12px var(--wb-accent-shadow-soft))' }}>
            {getEmoji(item.title)}
          </span>
          <div style={{
            position: 'absolute', bottom: 6, left: 6,
            width: 22, height: 22, borderRadius: '50%',
            background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(8px) saturate(140%)', WebkitBackdropFilter: 'blur(8px) saturate(140%)' as never,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 12, border: '1px solid rgba(255,255,255,0.12)',
          }}>
            {PRIO_EMOJI[item.priority] ?? '🙂'}
          </div>
        </div>
      )}

      {/* v2.1 Info panel — typography + CSS vars */}
      <div style={{ flex: 1, padding: '10px 12px', display: 'flex', flexDirection: 'column', justifyContent: 'center', minWidth: 0 }}>
        <div style={{
          fontSize: 14, fontWeight: 650,
          color: isPurchased ? 'var(--wb-text-muted)' : 'var(--wb-text)',
          lineHeight: 1.25, letterSpacing: '-0.015em',
          display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' as any, overflow: 'hidden',
          textDecoration: isPurchased ? 'line-through' : 'none', fontFamily: font,
        }}>
          {item.title}
          {(item.placementCount ?? 1) > 1 && (
            <span
              title={locale === 'ru' ? 'Общее желание — в нескольких списках' : 'Shared wish — in multiple wishlists'}
              style={{
                display: 'inline-flex', alignItems: 'center', gap: 3,
                marginLeft: 6, padding: '1px 6px', borderRadius: 6,
                fontSize: 10, fontWeight: 700, lineHeight: 1.2,
                color: 'var(--wb-accent-strong)',
                background: 'var(--wb-accent-soft)',
                verticalAlign: 'baseline', whiteSpace: 'nowrap',
              }}
            >
              🔗 {locale === 'ru' ? 'В ' : 'In '}{item.placementCount}
            </span>
          )}
        </div>

        <div style={{ display: 'flex', alignItems: 'baseline', gap: 8, marginTop: 5 }}>
          {item.price != null ? (
            <span style={{
              fontSize: 17, fontWeight: 700,
              color: isPurchased ? 'var(--wb-text-muted)' : 'var(--wb-text)',
              letterSpacing: '-0.03em', lineHeight: 1, fontFamily: font,
              fontFeatureSettings: '"tnum"',
              textDecoration: isPurchased ? 'line-through' : 'none',
            }}>
              {fmtPrice(item.price, locale, item.currency ?? 'RUB')}
            </span>
          ) : (
            <span style={{ fontSize: 12, color: 'var(--wb-text-muted)' }}>{t('price_not_set', locale)}</span>
          )}
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginTop: 6, flexWrap: 'wrap' }}>
          {item.sourceDomain && (
            <span style={{
              fontSize: 10, padding: '2px 7px', borderRadius: 6,
              color: 'var(--wb-accent-strong)',
              background: 'var(--wb-accent-soft)',
              border: '1px solid var(--wb-accent-soft-strong)',
              fontWeight: 600, whiteSpace: 'nowrap',
              fontFeatureSettings: '"tnum"',
            }}>
              {item.sourceDomain}
            </span>
          )}
          {/* Status chips */}
          {isGuest && item.status === 'available' && onReserve && !secretByMe && (
            <button
              onClick={(e) => { e.stopPropagation(); onReserve(item); }}
              style={{
                background: 'linear-gradient(135deg, var(--wb-accent), var(--wb-accent-deep))',
                color: '#fff', border: 'none', padding: '6px 12px', borderRadius: 10,
                fontSize: 11, fontWeight: 700, cursor: 'pointer', fontFamily: font, whiteSpace: 'nowrap',
                boxShadow: '0 4px 12px var(--wb-accent-shadow-soft), inset 0 1px 0 rgba(255,255,255,0.2)',
              }}
            >
              {t('reserve_btn', locale)}
            </button>
          )}
          {isGuest && secretByMe && (
            <span style={{
              display: 'inline-flex', alignItems: 'center',
              fontSize: 10, padding: '2px 8px', borderRadius: 6, fontWeight: 700,
              color: 'var(--wb-accent-strong)',
              background: 'var(--wb-accent-soft)',
              border: '1px solid var(--wb-accent-soft-strong)', whiteSpace: 'nowrap',
            }}>
              {t('sr_card_chip_secret', locale)}
            </span>
          )}
          {isGuest && isReservedByMe && (
            <>
              <span style={{ fontSize: 10, padding: '2px 7px', borderRadius: 6, fontWeight: 600, color: '#6ee7b7', background: 'rgba(52,211,153,0.1)' }}>
                {t('reserved_by_me', locale)}
              </span>
              {onUnreserve && <span onClick={(e) => { e.stopPropagation(); onUnreserve(item); }} style={{ fontSize: 10, color: '#555', cursor: 'pointer' }}>{t('cancel', locale)}</span>}
            </>
          )}
          {isGuest && isReserved && !isReservedByMe && (
            <span style={{ fontSize: 10, padding: '2px 7px', borderRadius: 6, fontWeight: 600, color: '#fbbf24', background: 'rgba(251,191,36,0.1)' }}>
              ⏳ {t('already_reserved', locale)}
            </span>
          )}
          {!isGuest && isReserved && (
            <span style={{ fontSize: 10, padding: '2px 7px', borderRadius: 6, fontWeight: 600, color: '#a599ff', background: 'rgba(124,106,255,0.1)' }}>
              🔒 {t('status_someone_reserved', locale)}
            </span>
          )}
          {isPurchased && (
            <span style={{ fontSize: 10, padding: '2px 7px', borderRadius: 6, fontWeight: 600, color: '#6ee7b7', background: 'rgba(52,211,153,0.1)' }}>
              🎉 {t('status_gifted', locale)}
            </span>
          )}
        </div>

        {sourceLabel && (
          <span style={{ display: 'inline-block', fontSize: 9, fontWeight: 500, color: C.textMuted, background: C.surface, border: `1px solid ${C.borderLight}`, padding: '1px 6px', borderRadius: 20, marginTop: 4 }}>
            {sourceLabel}
          </span>
        )}
      </div>
    </div>
  );
}

function WishCardShowcase({ item, onTap, locale, sourceLabel, isGuest, onReserve, onUnreserve, myActorHash, secretByMe }: {
  item: Item | GuestItem;
  onTap: (item: any) => void;
  locale: Locale;
  sourceLabel?: string;
  isGuest?: boolean;
  onReserve?: (item: any) => void;
  onUnreserve?: (item: any) => void;
  myActorHash?: string;
  secretByMe?: boolean;
}) {
  const [imgErr, setImgErr] = useState(false);
  const isPurchased = item.status === 'purchased';
  const isReserved = item.status === 'reserved';
  const isReservedByMe = isGuest && isReserved && !!(myActorHash) && (item as GuestItem).reservedByActorHash === myActorHash;
  const hasImg = !!item.imageUrl && !imgErr;
  const prioGrad = PRIO_GRADIENT[item.priority] ?? PRIO_GRADIENT[1];
  const glowColor = PRIO_GLOW[item.priority] ?? PRIO_GLOW[1];

  return (
    <div
      onClick={() => onTap(item)}
      style={{
        borderRadius: 20, overflow: 'hidden', position: 'relative',
        background: '#1c1c22', border: '1px solid rgba(255,255,255,0.05)',
        opacity: isPurchased ? 0.5 : 1,
        cursor: 'pointer', WebkitTapHighlightColor: 'transparent',
      }}
    >
      {/* Hero image or emoji */}
      {hasImg ? (
        <>
          <img
            src={item.imageUrl!}
            alt=""
            onError={() => setImgErr(true)}
            style={{ width: '100%', height: 200, objectFit: 'cover', display: 'block' }}
          />
          <div style={{
            position: 'absolute', top: 0, left: 0, right: 0, height: 200,
            background: 'linear-gradient(180deg, rgba(28,28,34,0) 40%, rgba(28,28,34,1) 100%)',
            pointerEvents: 'none',
          }} />
          {/* Float chips on image */}
          <div style={{ position: 'absolute', top: 12, left: 14, right: 14, display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div style={{
              background: 'rgba(0,0,0,0.55)', backdropFilter: 'blur(12px)', WebkitBackdropFilter: 'blur(12px)',
              border: '1px solid rgba(255,255,255,0.1)', borderRadius: 20, padding: '5px 12px',
              fontSize: 12, fontWeight: 600, color: '#fff', display: 'flex', alignItems: 'center', gap: 4,
            }}>
              <span>{PRIO_EMOJI[item.priority] ?? '🙂'}</span>
              {item.priority === 3 && <span style={{ color: 'rgba(255,255,255,0.7)', fontWeight: 500, fontSize: 11 }}>{t('prio_high_short', locale)}</span>}
            </div>
            {item.sourceDomain && (
              <div style={{
                background: 'rgba(0,0,0,0.55)', backdropFilter: 'blur(12px)', WebkitBackdropFilter: 'blur(12px)',
                border: '1px solid rgba(255,255,255,0.1)', borderRadius: 20, padding: '5px 12px',
                fontSize: 12, fontWeight: 600, color: '#fff',
              }}>
                {item.sourceDomain}
              </div>
            )}
          </div>
          {/* Gifted overlay chip */}
          {isPurchased && (
            <div style={{
              position: 'absolute', top: 12, right: 14,
              background: 'rgba(52,211,153,0.85)', borderRadius: 20, padding: '5px 12px',
              fontSize: 12, fontWeight: 600, color: '#fff',
            }}>
              🎉 {t('status_gifted', locale)}
            </div>
          )}
        </>
      ) : (
        <div style={{
          height: 130, display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 56, background: `linear-gradient(160deg, #1c1c22, ${C.accentSoft})`,
        }}>
          {getEmoji(item.title)}
        </div>
      )}

      {/* Body */}
      <div style={{ padding: '14px 18px 18px', position: 'relative' }}>
        {/* Priority glow */}
        <div style={{
          position: 'absolute', top: 0, left: '50%', transform: 'translateX(-50%)',
          width: '60%', height: 1, boxShadow: `0 0 20px 8px ${glowColor}`, opacity: 0.6,
        }} />

        <div style={{ fontSize: 17, fontWeight: 700, color: isPurchased ? '#666' : '#fff', lineHeight: 1.3, letterSpacing: '-0.01em', fontFamily: font, textDecoration: isPurchased ? 'line-through' : 'none' }}>
          {item.title}
          {(item.placementCount ?? 1) > 1 && (
            <span
              title={locale === 'ru' ? 'Общее желание — в нескольких списках' : 'Shared wish — in multiple wishlists'}
              style={{
                display: 'inline-flex', alignItems: 'center', gap: 3,
                marginLeft: 8, padding: '2px 8px', borderRadius: 8,
                fontSize: 11, fontWeight: 700, lineHeight: 1.2,
                color: '#a599ff', background: 'rgba(124,106,255,0.14)',
                verticalAlign: 'middle', whiteSpace: 'nowrap',
              }}
            >
              🔗 {locale === 'ru' ? 'В ' : 'In '}{item.placementCount}
            </span>
          )}
        </div>

        <div style={{ display: 'flex', alignItems: 'baseline', gap: 10, marginTop: 8 }}>
          {item.price != null ? (
            <span style={{ fontSize: 26, fontWeight: 900, color: isPurchased ? '#444' : '#fff', letterSpacing: '-0.04em', lineHeight: 1, fontFamily: font, textDecoration: isPurchased ? 'line-through' : 'none' }}>
              {fmtPrice(item.price, locale, item.currency ?? 'RUB')}
            </span>
          ) : (
            <span style={{ fontSize: 14, color: '#444', fontWeight: 500 }}>{t('price_not_set', locale)}</span>
          )}
          {!hasImg && !isPurchased && (
            <span style={{
              padding: '5px 10px', borderRadius: 8, fontSize: 12, fontWeight: 600,
              background: PRIO_BG[item.priority], color: PRIO_COLOR[item.priority],
              border: `1px solid ${PRIO_COLOR[item.priority]}20`,
            }}>
              {PRIO_EMOJI[item.priority]} {item.priority === 3 ? t('prio_high_short', locale) : item.priority === 2 ? t('prio_med_short', locale) : t('prio_low_short', locale)}
            </span>
          )}
        </div>

        {/* Domain link if no image */}
        {!hasImg && item.sourceDomain && (
          <div style={{ marginTop: 8, fontSize: 12, color: C.accent, fontWeight: 500, display: 'flex', alignItems: 'center', gap: 4 }}>
            🔗 <span>{item.sourceDomain}</span>
          </div>
        )}

        {/* Status / action row */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 12, flexWrap: 'wrap' }}>
          {isGuest && item.status === 'available' && onReserve && !secretByMe && (
            <button
              onClick={(e) => { e.stopPropagation(); onReserve(item); }}
              style={{
                display: 'inline-flex', alignItems: 'center', gap: 6,
                padding: '10px 20px', borderRadius: 12, border: 'none',
                background: 'linear-gradient(135deg, #7C6AFF, #5B4BD6)',
                color: '#fff', fontSize: 14, fontWeight: 700, cursor: 'pointer', fontFamily: font,
                boxShadow: '0 4px 16px rgba(124,106,255,0.35)',
              }}
            >
              {t('reserve_btn', locale)}
            </button>
          )}
          {isGuest && secretByMe && (
            <span style={{
              display: 'inline-flex', alignItems: 'center', gap: 5,
              padding: '7px 14px', borderRadius: 12, fontSize: 13, fontWeight: 600,
              background: 'linear-gradient(135deg, rgba(167,139,250,0.18), rgba(167,139,250,0.08))',
              color: '#C4A7FF', border: '1px solid rgba(167,139,250,0.25)',
            }}>
              {t('sr_card_chip_secret', locale)}
            </span>
          )}
          {isGuest && isReservedByMe && (
            <>
              <span style={{
                display: 'inline-flex', alignItems: 'center', gap: 5,
                padding: '7px 14px', borderRadius: 12, fontSize: 13, fontWeight: 600,
                background: 'linear-gradient(135deg, rgba(52,211,153,0.15), rgba(52,211,153,0.08))',
                color: '#6ee7b7', border: '1px solid rgba(52,211,153,0.2)',
              }}>
                {t('reserved_by_me', locale)}
              </span>
              {onUnreserve && <span onClick={(e) => { e.stopPropagation(); onUnreserve(item); }} style={{ fontSize: 12, color: '#555', cursor: 'pointer' }}>{t('cancel', locale)}</span>}
            </>
          )}
          {isGuest && isReserved && !isReservedByMe && (
            <span style={{
              padding: '7px 14px', borderRadius: 12, fontSize: 13, fontWeight: 600,
              background: 'rgba(251,191,36,0.1)', color: '#fbbf24', border: '1px solid rgba(251,191,36,0.15)',
            }}>
              ⏳ {t('already_reserved', locale)}
            </span>
          )}
          {!isGuest && isReserved && (
            <span style={{
              display: 'inline-flex', alignItems: 'center', gap: 5,
              padding: '7px 14px', borderRadius: 12, fontSize: 13, fontWeight: 600,
              background: 'linear-gradient(135deg, rgba(124,106,255,0.15), rgba(124,106,255,0.08))',
              color: '#a599ff', border: '1px solid rgba(124,106,255,0.2)',
            }}>
              🔒 {t('status_someone_reserved', locale)}
            </span>
          )}
          {isPurchased && !hasImg && (
            <span style={{
              padding: '7px 14px', borderRadius: 12, fontSize: 13, fontWeight: 600,
              background: 'linear-gradient(135deg, rgba(52,211,153,0.15), rgba(52,211,153,0.08))',
              color: '#6ee7b7', border: '1px solid rgba(52,211,153,0.2)',
            }}>
              🎉 {t('status_gifted', locale)}
            </span>
          )}
        </div>

        {sourceLabel && (
          <span style={{ display: 'inline-block', fontSize: 9, fontWeight: 500, color: C.textMuted, background: C.surface, border: `1px solid ${C.borderLight}`, padding: '1px 6px', borderRadius: 20, marginTop: 8 }}>
            {sourceLabel}
          </span>
        )}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════
// RESERVATION CARD (for "My Reservations" section)
// ═══════════════════════════════════════════════════════

function ReservationCard({ item, onTap, onUnreserve, onExtend, onGroupGift, animDelay, locale, now }: {
  item: ReservationItem;
  onTap: () => void;
  onUnreserve: () => void;
  onExtend?: () => void;
  onGroupGift?: () => void;
  animDelay: number;
  locale: Locale;
  now: number;
}) {
  const meta = item.meta;
  const isSmart = meta?.isSmartRes && meta.expiresAt;
  const expiresMs = isSmart ? new Date(meta!.expiresAt!).getTime() : 0;
  const remainMs = expiresMs - now;
  const isExpired = isSmart && remainMs <= 0;
  const isExpiring = isSmart && !isExpired && meta!.isExpiringSoon;
  return (
    <div
      onClick={onTap}
      className="wb-card-pressed"
      style={{
        background: 'var(--wb-card)',
        border: '1px solid var(--wb-border)',
        borderRadius: 18, padding: 16,
        display: 'flex', gap: 14, alignItems: 'flex-start',
        cursor: 'pointer',
        WebkitTapHighlightColor: 'transparent',
        WebkitBackdropFilter: 'blur(14px)' as never,
        backdropFilter: 'blur(14px)' as never,
        transition: 'all 0.15s cubic-bezier(0.4, 0, 0.2, 1)',
        animation: `fadeIn 0.3s ease ${animDelay}s both`,
      }}
    >
      <ItemThumb item={item} />
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{
            fontSize: 15, fontWeight: 600, fontFamily: font,
            color: 'var(--wb-text)',
            lineHeight: 1.3, paddingRight: 8,
            letterSpacing: '-0.015em',
          }}>
            {item.title}
          </div>
          {item.unreadComments > 0 && (
            <span style={{
              minWidth: 20, height: 20, borderRadius: 10,
              background: 'var(--wb-accent)', color: '#fff',
              fontSize: 11, fontWeight: 700,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              padding: '0 6px', flexShrink: 0,
              boxShadow: '0 0 10px var(--wb-accent-shadow-soft)',
            }}>
              {item.unreadComments}
            </span>
          )}
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 4, flexWrap: 'wrap' }}>
          {item.price != null && (
            <span style={{
              fontSize: 13, fontWeight: 650,
              color: 'var(--wb-text-secondary)',
              fontFamily: font,
              fontFeatureSettings: '"tnum"',
            }}>
              {fmtPrice(item.price, locale, item.currency ?? 'RUB')}
            </span>
          )}
          {item.groupGiftRole ? (
            <Chip tone="accent" icon="👥">
              {t('gg_reservation_badge', locale)}
            </Chip>
          ) : (
            <Chip tone="success">
              {t('reservations_reserved', locale)}
            </Chip>
          )}
        </div>
        {item.groupGiftRole && (
          <div style={{ fontSize: 12, color: 'var(--wb-text-muted)', marginTop: 6, letterSpacing: '-0.003em' }}>
            {item.groupGiftRole === 'organizer'
              ? t('gg_reservation_you_organizer', locale)
              : `${t('gg_reservation_organizer', locale)}: ${item.groupGiftOrganizerName ?? ''}`}
          </div>
        )}
        {isSmart && (
          <div style={{ marginTop: 8 }}>
            {isExpired ? (
              <span style={{ fontSize: 12, color: C.red, fontWeight: 600 }}>{t('smart_res_expired', locale)}</span>
            ) : (
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
                <Chip tone={isExpiring ? 'warning' : 'success'}>
                  ⏱ {formatSmartResTimer(remainMs)}
                </Chip>
                {meta!.extensionCount > 0 && (
                  <span style={{ fontSize: 10, color: C.textMuted }}>{t('smart_res_extended_badge', locale, { count: String(meta!.extensionCount), max: String(meta!.maxExtensions) })}</span>
                )}
              </div>
            )}
            {/* Progress bar */}
            {!isExpired && meta!.expiresAt && (() => {
              const ttlMs = (meta!.maxExtensions > 0 ? meta!.maxExtensions : 1) * 3600000 * 72; // approximate
              const pct = Math.max(0, Math.min(100, (remainMs / (ttlMs > 0 ? ttlMs : 72 * 3600000)) * 100));
              return (
                <div style={{ marginTop: 6, height: 3, borderRadius: 2, background: C.surfaceHover, overflow: 'hidden' }}>
                  <div style={{ height: '100%', borderRadius: 2, background: isExpiring ? C.orange : C.green, width: `${pct}%`, transition: 'width 1s linear' }} />
                </div>
              );
            })()}
          </div>
        )}
        <div style={{ marginTop: 10, display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          {isSmart && !isExpired && meta!.canExtend && onExtend && (
            <button
              onClick={(e) => { e.stopPropagation(); onExtend(); }}
              style={{
                background: 'var(--wb-accent-soft)',
                border: '1px solid var(--wb-accent-soft-strong)',
                borderRadius: 12, padding: '7px 14px', fontSize: 12,
                color: 'var(--wb-accent-strong)',
                cursor: 'pointer', fontFamily: font, fontWeight: 650,
                letterSpacing: '-0.005em',
              }}
            >
              {t('smart_res_extend_btn', locale)}
            </button>
          )}
          {onGroupGift && (
            <button
              onClick={(e) => { e.stopPropagation(); onGroupGift(); }}
              style={{
                background: 'var(--wb-accent-soft)',
                border: '1px solid var(--wb-accent-soft-strong)',
                borderRadius: 12, padding: '7px 14px', fontSize: 12,
                color: 'var(--wb-accent-strong)',
                cursor: 'pointer', fontFamily: font, fontWeight: 650,
                letterSpacing: '-0.005em',
              }}
            >
              👥 {t('gg_reservation_badge', locale)}
            </button>
          )}
          {item.groupGiftRole !== 'participant' && (
            <button
              onClick={(e) => { e.stopPropagation(); onUnreserve(); }}
              style={{
                background: 'var(--wb-danger-soft)',
                border: '1px solid rgba(251,113,133,0.28)',
                borderRadius: 12, padding: '7px 14px', fontSize: 12,
                color: 'var(--wb-danger)',
                cursor: 'pointer', fontFamily: font, fontWeight: 650,
                letterSpacing: '-0.005em',
              }}
            >
              {t('reservations_unreserve', locale)}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════
// COMMENTS THREAD (module-level to keep stable identity)
// ═══════════════════════════════════════════════════════

function CommentsThread({
  commentRole, comments, commentText, setCommentText, commentSending, myActorHash,
  onDeleteComment, onSendComment, isArchive, locale,
  replyingTo, onStartReply, onCancelReply,
  expandInitially, highlightCommentId, commentNodeRefs,
}: {
  commentRole: 'owner' | 'reserver' | null;
  comments: CommentDTO[];
  commentText: string;
  setCommentText: (t: string) => void;
  commentSending: boolean;
  myActorHash: string;
  locale: Locale;
  onDeleteComment: (id: string) => void;
  onSendComment: () => void;
  isArchive?: boolean;
  replyingTo: CommentDTO | null;
  onStartReply: (c: CommentDTO) => void;
  onCancelReply: () => void;
  expandInitially?: boolean;
  highlightCommentId?: string | null;
  commentNodeRefs?: React.MutableRefObject<Map<string, HTMLDivElement>>;
}) {
  const [expanded, setExpanded] = useState(!!expandInitially);
  // React to expandInitially becoming true later (e.g. when deeplink-entry effect fires)
  useEffect(() => { if (expandInitially) setExpanded(true); }, [expandInitially]);
  const scrollRef = useRef<HTMLDivElement>(null);

  if (!commentRole) return null;

  const canDelete = (c: CommentDTO) => {
    if (c.type === 'SYSTEM') return false;
    if (commentRole === 'owner') return true;
    return c.authorActorHash === myActorHash;
  };

  const isMine = (c: CommentDTO) => c.authorActorHash === myActorHash;

  /* ── Collapsed: accent CTA button per mockup ── */
  if (!expanded) {
    const badgeText = comments.length > 0
      ? `${comments.length} ${locale === 'ru'
          ? (comments.length % 10 === 1 && comments.length % 100 !== 11 ? 'новый' : 'новых')
          : t('comments_badge_new', locale)}`
      : null;
    return (
      <button
        onClick={() => setExpanded(true)}
        style={{
          ...btnBase,
          width: '100%', display: 'flex', alignItems: 'center', gap: 10,
          background: C.accent, color: '#fff', border: 'none', borderRadius: 14,
          padding: '15px 18px', marginTop: 20, cursor: 'pointer',
          justifyContent: 'flex-start',
          boxShadow: '0 2px 12px rgba(124,106,255,0.25)',
        }}
      >
        <span style={{ fontSize: 18, lineHeight: 1, flexShrink: 0 }}>💬</span>
        <span style={{ flex: 1, fontSize: 15, fontWeight: 700, color: '#fff', fontFamily: font, textAlign: 'left' }}>
          {t('comments_title', locale)}
        </span>
        {badgeText && (
          <span style={{
            fontSize: 12, fontWeight: 700, color: '#fff',
            background: 'rgba(255,255,255,0.22)', padding: '3px 10px', borderRadius: 10,
            lineHeight: '18px', flexShrink: 0, whiteSpace: 'nowrap',
          }}>
            {badgeText}
          </span>
        )}
      </button>
    );
  }

  /* ── Expanded: full thread with scroll ── */
  // Cap the whole card at 75vh — on a wish with many comments the composer used to
  // slide off-screen because messages pushed page height past the viewport. With a
  // flex column + inner scroll area, the header/subtitle/composer stay visible
  // while the message list scrolls internally.
  return (
    <div style={{
      marginTop: 20, background: C.surface, borderRadius: 14, overflow: 'hidden', animation: 'fadeIn 0.2s ease',
      display: 'flex', flexDirection: 'column', maxHeight: '75vh',
    }}>
      {/* Header — tap to collapse */}
      <div
        onClick={() => setExpanded(false)}
        style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: '12px 14px 6px', cursor: 'pointer', flexShrink: 0,
        }}
      >
        <span style={{ fontSize: 15, lineHeight: 1 }}>💬</span>
        <span style={{ fontSize: 14, fontWeight: 700, color: C.text, fontFamily: font }}>{t('comments_title', locale)}</span>
        <span style={{ fontSize: 11, color: C.textMuted, background: C.bg, padding: '2px 8px', borderRadius: 8 }}>{comments.length}</span>
        <span style={{ fontSize: 12, color: C.textMuted, marginLeft: 'auto', transform: 'rotate(90deg)', display: 'inline-block' }}>›</span>
      </div>

      <div style={{ fontSize: 11, color: C.textMuted, padding: '0 14px', marginBottom: 10, lineHeight: 1.4, flexShrink: 0 }}>
        {t('comments_subtitle', locale)}
      </div>

      {isArchive && (
        <Banner tone="warning" style={{ margin: '0 14px 10px', flexShrink: 0 }}>
          {t('comments_archive_warning', locale)}
        </Banner>
      )}

      {/* Messages — scrollable. flex:1 + minHeight:0 lets this area shrink/grow
          while the composer+chip below stay pinned to the bottom of the card. */}
      <div ref={scrollRef} style={{ flex: 1, minHeight: 0, overflowY: 'auto', padding: '0 14px', WebkitOverflowScrolling: 'touch' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
          {comments.length === 0 && (
            <div style={{ textAlign: 'center', fontSize: 13, color: C.textMuted, padding: '12px 0 8px' }}>
              {t('comments_empty', locale)}
            </div>
          )}
          {comments.map(c => (
            c.type === 'SYSTEM' ? (
              <div key={c.id} style={{
                textAlign: 'center', fontSize: 11, color: C.textMuted,
                padding: '5px 12px', background: C.bg, borderRadius: 10, margin: '3px 0',
                lineHeight: 1.4,
              }}>
                {c.text} · {new Date(c.createdAt).toLocaleString(toIntlLocale(locale), { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })}
              </div>
            ) : (
              <div
                key={c.id}
                ref={(node) => {
                  if (!commentNodeRefs) return;
                  if (node) commentNodeRefs.current.set(c.id, node);
                  else commentNodeRefs.current.delete(c.id);
                }}
                style={{
                  alignSelf: isMine(c) ? 'flex-end' : 'flex-start',
                  maxWidth: '75%',
                  transition: 'box-shadow 0.2s ease',
                  borderRadius: 18,
                  ...(highlightCommentId === c.id
                    ? { animation: 'commentPulse 2.5s ease-out', padding: 2, margin: -2 }
                    : {}),
                }}
              >
                {/* Reply marker — shown above the bubble if this comment has a parent */}
                {c.parentCommentId && (
                  <div style={{
                    fontSize: 11, color: C.textMuted, fontFamily: font,
                    marginBottom: 4, lineHeight: 1.3,
                    textAlign: isMine(c) ? 'right' : 'left',
                    paddingLeft: isMine(c) ? 0 : 6,
                    paddingRight: isMine(c) ? 6 : 0,
                  }}>
                    {c.parentPreview && !c.parentPreview.deleted ? (
                      <>
                        <span style={{ opacity: 0.7 }}>↳ {t('comments_reply_tag', locale)}</span>
                        {' '}
                        <span style={{ opacity: 0.9 }}>
                          «{c.parentPreview.text.length > 40
                            ? c.parentPreview.text.slice(0, 40) + '…'
                            : c.parentPreview.text}»
                        </span>
                      </>
                    ) : (
                      <span style={{ opacity: 0.6, fontStyle: 'italic' }}>
                        ↳ {t('comments_reply_deleted_tag', locale)}
                      </span>
                    )}
                  </div>
                )}
                {!isMine(c) && (
                  <div style={{ fontSize: 12, color: C.accent, marginBottom: 2, fontWeight: 600, fontFamily: font }}>
                    {c.authorDisplayName ?? t('comments_anon', locale)}
                  </div>
                )}
                {isMine(c) && (
                  <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.4)', marginBottom: 2, fontWeight: 500, fontFamily: font, textAlign: 'right' }}>
                    {t('comments_me', locale)}
                  </div>
                )}
                <div style={{
                  padding: '10px 14px', borderRadius: 16,
                  background: isMine(c) ? C.accent : C.card,
                  color: isMine(c) ? '#fff' : C.text,
                  fontSize: 14, lineHeight: 1.4,
                  border: isMine(c) ? 'none' : `1px solid ${C.border}`,
                }}>
                  {c.text}
                  <div style={{
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    marginTop: 4, gap: 8,
                  }}>
                    <span style={{
                      fontSize: 11,
                      color: isMine(c) ? 'rgba(255,255,255,0.45)' : C.textMuted,
                    }}>
                      {new Date(c.createdAt).toLocaleTimeString(toIntlLocale(locale), { hour: '2-digit', minute: '2-digit' })}
                    </span>
                    <div style={{ display: 'flex', gap: 2 }}>
                      {/* Reply button — only on other users' top-level USER comments,
                          when composer is enabled. Hidden on own bubbles (replying to yourself
                          is nonsensical) and on nested replies (one-level cap). */}
                      {!isArchive && !isMine(c) && c.parentCommentId === null && c.type === 'USER' && (
                        <button
                          onClick={() => onStartReply(c)}
                          aria-label={t('comments_reply_header', locale)}
                          style={{
                            background: 'none', border: 'none', padding: '4px 6px', cursor: 'pointer',
                            fontSize: 13, lineHeight: 1, color: C.accent,
                          }}
                        >
                          ↩
                        </button>
                      )}
                      {canDelete(c) && !isArchive && (
                        <button
                          onClick={() => void onDeleteComment(c.id)}
                          style={{
                            background: 'none', border: 'none', padding: '4px 6px', cursor: 'pointer',
                            fontSize: 12, color: isMine(c) ? 'rgba(255,255,255,0.35)' : C.textMuted,
                          }}
                        >
                          ✕
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            )
          ))}
        </div>
      </div>

      {/* Composer */}
      {!isArchive && (
        <>
          {/* Reply chip — shown above the composer when replyingTo is set */}
          {replyingTo && (
            <div style={{
              display: 'flex', alignItems: 'center', gap: 10,
              margin: '6px 14px 0', padding: '8px 10px',
              background: C.accentSoft, borderLeft: `3px solid ${C.accent}`, borderRadius: 10,
              minHeight: 40, flexShrink: 0,
            }}>
              <div style={{ flex: 1, minWidth: 0, display: 'flex', flexDirection: 'column', gap: 2 }}>
                <span style={{ fontSize: 11, color: C.accent, fontWeight: 700, fontFamily: font, letterSpacing: 0.2 }}>
                  {t('comments_reply_header', locale)}
                </span>
                <span style={{
                  fontSize: 12, color: C.text, fontFamily: font, lineHeight: 1.3,
                  overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                }}>
                  {(replyingTo.authorDisplayName ?? t('comments_anon', locale))}: «{replyingTo.text.length > 80 ? replyingTo.text.slice(0, 80) + '…' : replyingTo.text}»
                </span>
              </div>
              <button
                onClick={() => onCancelReply()}
                aria-label="Cancel reply"
                style={{
                  background: 'none', border: 'none', padding: 6, cursor: 'pointer',
                  fontSize: 14, color: C.textMuted, lineHeight: 1, flexShrink: 0,
                }}
              >
                ✕
              </button>
            </div>
          )}
          <div style={{ display: 'flex', gap: 8, padding: '10px 14px 14px', alignItems: 'flex-end', flexShrink: 0 }}>
            <div style={{ flex: 1, position: 'relative' }}>
              <textarea
                style={{
                  ...inputStyle,
                  minHeight: 40, maxHeight: 80, resize: 'none',
                  padding: '10px 40px 10px 14px',
                  borderRadius: 12, fontSize: 14,
                  background: C.bg, lineHeight: 1.4,
                }}
                placeholder={replyingTo ? t('comments_reply_placeholder', locale) : t('comments_placeholder', locale)}
                value={commentText}
                onChange={(e) => { setCommentText(e.target.value.slice(0, 300)); growTextarea(e.target); }}
                maxLength={300}
                onFocus={(e) => handleTextareaFocus(e.currentTarget)}
                onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); void onSendComment(); } }}
              />
              <span style={{
                position: 'absolute', right: 12, bottom: 8,
                fontSize: 9, color: C.textMuted,
                opacity: commentText.length > 280 ? 1 : 0.4,
                ...(commentText.length > 280 ? { color: C.orange } : {}),
              }}>
                {commentText.length}/300
              </span>
            </div>
            <button
              onClick={() => void onSendComment()}
              disabled={!commentText.trim() || commentSending}
              style={{
                ...btnPrimary, width: 36, height: 36, padding: 0, borderRadius: 18,
                opacity: commentText.trim() ? 1 : 0.35, flexShrink: 0, fontSize: 14,
              }}
            >
              {commentSending ? '…' : '↑'}
            </button>
          </div>
        </>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════
// ADD-ON OFFER HELPERS (module-level, no state)
// ═══════════════════════════════════════════════════════

const CONTEXT_ADDON_SKUS: Partial<Record<UpsellContext, string[]>> = {
  wishlist_limit:    ['extra_wishlist_slot'],
  item_limit:        ['extra_items_5', 'extra_items_15'],
  subscription_limit:['extra_subscription_slot'],
  hints:             ['hints_pack_5', 'hints_pack_10'],
  url_import:        ['import_pack_10', 'import_pack_25'],
  reservation_pro:   ['reservation_pro_unlock'],
  smart_reservations:['smart_reservations_unlock'],
};

function getAddonOffers(locale: Locale): Record<string, { title: string; tag: string }> {
  return {
    extra_wishlist_slot:     { title: t('addon_extra_wishlist_title', locale),      tag: t('addon_tag_extra_wishlist_slot', locale) },
    extra_subscription_slot:{ title: t('addon_extra_subscription_title', locale),  tag: t('addon_tag_extra_subscription_slot', locale) },
    extra_items_5:          { title: t('addon_extra_items_5_title', locale),        tag: t('addon_tag_extra_items_5', locale) },
    extra_items_15:         { title: t('addon_extra_items_15_title', locale),       tag: t('addon_tag_extra_items_15', locale) },
    hints_pack_5:           { title: t('addon_hints_pack_5_title', locale),         tag: t('addon_tag_hints_pack_5', locale) },
    hints_pack_10:          { title: t('addon_hints_pack_10_title', locale),        tag: t('addon_tag_hints_pack_10', locale) },
    import_pack_10:         { title: t('addon_import_pack_10_title', locale),       tag: t('addon_tag_import_pack_10', locale) },
    import_pack_25:         { title: t('addon_import_pack_25_title', locale),       tag: t('addon_tag_import_pack_25', locale) },
    seasonal_decoration:    { title: t('addon_seasonal_decoration_title', locale),  tag: t('addon_seasonal_decoration_desc', locale) },
    gift_notes_unlock:      { title: t('addon_gift_notes_title', locale),           tag: t('addon_gift_notes_desc', locale) },
    reservation_pro_unlock: { title: t('addon_title_reservation_pro_unlock', locale), tag: t('addon_desc_reservation_pro_unlock', locale) },
    smart_reservations_unlock: { title: t('addon_title_smart_reservations_unlock', locale), tag: t('addon_desc_smart_reservations_unlock', locale) },
  };
}

// ═══════════════════════════════════════════════════════
// PRO UPSELL SHEET (context-aware)
// ═══════════════════════════════════════════════════════

function ProUpsellSheet({ state, onClose, onUpgrade, checkoutLoading, onBuyAddon, addonCheckoutLoading, availableSkus, cappedAddonCodes, locale, referralConfig, onOpenReferral, onReferralImpression }: {
  state: UpsellSheetState;
  onClose: () => void;
  onUpgrade: (plan: 'monthly' | 'yearly') => void;
  checkoutLoading: boolean;
  onBuyAddon: (skuCode: string, targetId?: string) => void;
  addonCheckoutLoading: boolean;
  availableSkus: SkuInfo[];
  cappedAddonCodes: string[];
  locale: Locale;
  // Structural — we only use these fields from the full config.
  referralConfig: {
    enabled: boolean;
    inRollout: boolean;
    reward: { daysPerRef: number };
    ui: { entryPointPaywall: boolean };
  } | null;
  onOpenReferral: () => void;
  onReferralImpression: (context: string) => void;
}) {
  const content = state ? getUpsellContent(locale)[state.context] : null;
  const [selectedPlan, setSelectedPlan] = useState<'monthly' | 'yearly'>('yearly');
  const monthlyPrice = PRO_PRICE_MONTHLY_STARS;
  const yearlyPrice = PRO_PRICE_YEARLY_STARS;
  const yearlyPerMonth = Math.round(yearlyPrice / 12);
  // Fire impression when the paywall becomes visible AND the referral alt
  // CTA would render. Debounced per-open via ref so we don't double-fire on
  // re-renders within the same paywall open. Resets on close.
  const paywallImpressionFiredRef = useRef<string | null>(null);
  useEffect(() => {
    if (!state) {
      paywallImpressionFiredRef.current = null;
      return;
    }
    const shouldRender = !!(referralConfig?.enabled && referralConfig.inRollout && referralConfig.ui.entryPointPaywall);
    if (!shouldRender) return;
    // Only fire once per (context, paywall-open) pair.
    const key = state.context;
    if (paywallImpressionFiredRef.current === key) return;
    paywallImpressionFiredRef.current = key;
    onReferralImpression(key);
  }, [state, referralConfig, onReferralImpression]);

  // Group PRO benefits into 3 sections per approved v2-paywall mockup:
  //   - "Новое в PRO": isNew && !resSection (showcase, secret-res, curated, don't-gift)
  //   - "Reservation PRO": resSection (smart-res, notes, reminders, bought, filters, history)
  //   - "Основные PRO": everything else (limits, comments, url-import, hints, subs, categories, calendar)
  const benefits = useMemo(() => getProBenefits(locale), [locale]);
  const secNew = useMemo(() => benefits.filter(b => b.isNew && !b.resSection), [benefits]);
  const secRes = useMemo(() => benefits.filter(b => b.resSection), [benefits]);
  const secCore = useMemo(() => benefits.filter(b => !b.isNew && !b.resSection), [benefits]);
  // Render a single feature row (used inside each PRO-features card).
  // v2.1 FeatureRow — glass surface with accent-soft thumb + hairline divider
  const FeatureRow = ({ icon, title, subtitle, isNew, last }: { icon: string; title: string; subtitle: string; isNew?: boolean; last?: boolean }) => (
    <div style={{
      display: 'flex', gap: 14, padding: '14px 16px', alignItems: 'center',
      borderBottom: last ? 'none' : '1px solid var(--wb-hairline)',
    }}>
      <div style={{
        width: 42, height: 42, borderRadius: 13,
        background: isNew
          ? 'linear-gradient(135deg, var(--wb-accent-soft-strong), var(--wb-accent-soft))'
          : 'linear-gradient(135deg, var(--wb-accent-soft-strong), var(--wb-accent-soft))',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 20, flexShrink: 0,
        boxShadow: 'inset 0 1px 0 rgba(255,255,255,0.08)',
      }}>{icon}</div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontSize: 14.5, fontWeight: 600, color: 'var(--wb-text)', display: 'flex', gap: 6, alignItems: 'center', letterSpacing: '-0.012em', flexWrap: 'wrap' }}>
          <span>{title}</span>
          {isNew && <Chip tone="new" size="sm">{t('paywall_new_badge', locale)}</Chip>}
        </div>
        <div style={{ fontSize: 12.5, color: 'var(--wb-text-secondary)', marginTop: 2, lineHeight: 1.4, letterSpacing: '-0.003em' }}>{subtitle}</div>
      </div>
    </div>
  );

  // v2.1 SectionLabel — small uppercase muted, 0.7px letter-spacing (matches .wb-section-hdr h2).
  const SectionLabel = ({ children, accent }: { children: ReactNode; accent?: boolean }) => (
    <div style={{
      fontSize: 12, fontWeight: 600,
      color: accent ? 'var(--wb-accent-strong)' : 'var(--wb-text-muted)',
      letterSpacing: '0.7px', textTransform: 'uppercase',
      margin: '20px 8px 10px',
    }}>{children}</div>
  );

  const ctaPrice = selectedPlan === 'yearly' ? yearlyPrice : monthlyPrice;
  const ctaLabel = checkoutLoading
    ? t('upsell_checkout_loading', locale)
    : selectedPlan === 'yearly'
      ? t('paywall_cta_yearly', locale, { price: String(ctaPrice) })
      : t('paywall_cta_monthly', locale, { price: String(ctaPrice) });

  return (
    <BottomSheet isOpen={state !== null} onClose={onClose}>
      {content && (
        <div style={{ padding: '0 0 8px' }}>
          {/* ── Context chip: why this paywall opened ── */}
          {content && (
            <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 12 }}>
              <Chip tone="accent" size="md" icon={<span>{content.emoji}</span>}>
                {content.title}
              </Chip>
            </div>
          )}

          {/* ── v2.1 Hero — accent-shadow emoji glow + gradient PRO word ── */}
          <Card variant="hero" padding="lg" style={{ textAlign: 'center', margin: '4px 0 18px' }}>
            <div style={{ fontSize: 64, marginBottom: 8, filter: 'drop-shadow(0 16px 32px var(--wb-accent-shadow))', lineHeight: 1 }}>👑</div>
            {(() => {
              // v2.1 pattern: wrap "PRO" in a gradient-text span. The translated
              // string already includes "PRO" — split on it so the rest stays
              // in the locale's own copy ("WishBoard PRO" / "WishBoard PRO" / etc).
              const rawTitle = t('paywall_hero_title', locale);
              const idx = rawTitle.indexOf('PRO');
              const before = idx >= 0 ? rawTitle.slice(0, idx) : rawTitle;
              const after = idx >= 0 ? rawTitle.slice(idx + 3) : '';
              const hasPro = idx >= 0;
              return (
                <div style={{ fontSize: 32, fontWeight: 700, lineHeight: 1.05, letterSpacing: '-0.035em', color: '#fff' }}>
                  {before}
                  {hasPro && (
                    <span style={{
                      background: 'linear-gradient(135deg, #FFFFFF 20%, #C8BDFF 80%)',
                      WebkitBackgroundClip: 'text', backgroundClip: 'text',
                      WebkitTextFillColor: 'transparent', color: 'transparent',
                    }}>PRO</span>
                  )}
                  {after}
                </div>
              );
            })()}
            <div style={{ fontSize: 15, marginTop: 8, lineHeight: 1.45, fontWeight: 500, color: 'rgba(255,255,255,0.92)', whiteSpace: 'pre-line', letterSpacing: '-0.005em' }}>
              {t('paywall_hero_sub', locale)}
            </div>
          </Card>

          {/* ── Section 1: What's NEW in PRO ── */}
          {secNew.length > 0 && (
            <>
              <SectionLabel accent>✨ {t('paywall_sec_new', locale)}</SectionLabel>
              <Card padding="none">
                {secNew.map((b, i) => (
                  <FeatureRow key={`new-${i}`} icon={b.icon} title={b.title} subtitle={b.subtitle} isNew last={i === secNew.length - 1} />
                ))}
              </Card>
            </>
          )}

          {/* ── Section 2: Reservation PRO ── */}
          {secRes.length > 0 && (
            <>
              <SectionLabel>⏱ {t('paywall_sec_res', locale)}</SectionLabel>
              <Card padding="none">
                {secRes.map((b, i) => (
                  <FeatureRow key={`res-${i}`} icon={b.icon} title={b.title} subtitle={b.subtitle} last={i === secRes.length - 1} />
                ))}
              </Card>
            </>
          )}

          {/* ── Section 3: Core PRO ── */}
          {secCore.length > 0 && (
            <>
              <SectionLabel>📦 {t('paywall_sec_core', locale)}</SectionLabel>
              <Card padding="none">
                {secCore.map((b, i) => (
                  <FeatureRow key={`core-${i}`} icon={b.icon} title={b.title} subtitle={b.subtitle} last={i === secCore.length - 1} />
                ))}
              </Card>
            </>
          )}

          {/* ── Plan selector (monthly vs yearly) ──
              Selected → Card.current (accent-tinted) with role=button;
              unselected → Card.interactive. Keyboard-a11y via role+aria. */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginTop: 18 }}>
            {(['monthly', 'yearly'] as const).map((plan) => {
              const isYear = plan === 'yearly';
              const isSelected = selectedPlan === plan;
              return (
                <Card
                  key={plan}
                  variant={isSelected ? 'current' : 'interactive'}
                  padding="sm"
                  onClick={() => setSelectedPlan(plan)}
                  role="button"
                  aria-pressed={isSelected}
                  style={{ position: 'relative', textAlign: 'start' }}
                >
                  {isYear && (
                    <div style={{
                      position: 'absolute', top: -9, right: 10,
                      background: C.green, color: '#000',
                      padding: '3px 8px', borderRadius: 100,
                      fontSize: 10, fontWeight: 800, letterSpacing: '0.3px',
                    }}>{t('paywall_save_badge', locale)}</div>
                  )}
                  <div style={{
                    fontSize: 11, color: isSelected ? C.accent : C.textMuted,
                    marginBottom: 4, fontWeight: 700, letterSpacing: '0.05em', textTransform: 'uppercase',
                  }}>
                    {t(isYear ? 'paywall_plan_yearly_name' : 'paywall_plan_monthly_name', locale)}
                  </div>
                  <div style={{ fontSize: 22, fontWeight: 800, letterSpacing: '-0.02em', color: C.text }}>
                    {isYear ? yearlyPrice : monthlyPrice} ⭐
                  </div>
                  <div style={{ fontSize: 11, color: C.textMuted, marginTop: 3 }}>
                    {isYear
                      ? t('paywall_plan_yearly_per', locale, { perMonth: String(yearlyPerMonth) })
                      : t('paywall_plan_monthly_per', locale)}
                  </div>
                </Card>
              );
            })}
          </div>

          {/* ── Referral alt CTA — only when program is live ── */}
          {referralConfig && referralConfig.enabled && referralConfig.inRollout && referralConfig.ui.entryPointPaywall && (
            <div
              onClick={onOpenReferral}
              style={{
                marginTop: 14, padding: 14, borderRadius: 14,
                background: 'rgba(124,106,255,0.04)',
                border: `1px dashed rgba(124,106,255,0.25)`,
                cursor: 'pointer',
                display: 'flex', gap: 12, alignItems: 'center', textAlign: 'start',
              }}
            >
              <div style={{
                width: 32, height: 32, borderRadius: 10, background: C.accentSoft,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 18, flexShrink: 0,
              }}>🎁</div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: C.accent }}>
                  {t('referral_paywall_alt_title', locale)}
                </div>
                <div style={{ fontSize: 11, color: C.textMuted, marginTop: 2, lineHeight: 1.4 }}>
                  {t('referral_paywall_alt_sub', locale, { days: String(referralConfig.reward.daysPerRef) })}
                </div>
              </div>
              <div style={{ color: C.accent, fontSize: 16, flexShrink: 0 }}>›</div>
            </div>
          )}

          {/* ── One-time add-on offers (limit-gate contexts only) ── */}
          {(() => {
            const contextSkuCodes = state?.context ? (CONTEXT_ADDON_SKUS[state.context] ?? []) : [];
            const skusToShow = contextSkuCodes
              .map(code => availableSkus.find(s => s.code === code))
              .filter((s): s is SkuInfo => s !== undefined);
            if (skusToShow.length === 0) return null;
            const offers = getAddonOffers(locale);
            const isLoading = addonCheckoutLoading || checkoutLoading;
            return (
              <div style={{ marginTop: 18 }}>
                <div style={{ textAlign: 'start', marginBottom: 10 }}>
                  <div style={{ fontSize: 13, fontWeight: 700, color: C.textSec, letterSpacing: 0.1 }}>
                    {t('addon_section_header', locale)}
                  </div>
                  <div style={{ fontSize: 12, color: C.textMuted, marginTop: 2 }}>
                    {t('addon_section_hint', locale)}
                  </div>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  {skusToShow.map(sku => {
                    const offer = offers[sku.code];
                    if (!offer) return null;
                    const isCapped = cappedAddonCodes.includes(sku.code);
                    return (
                      <Card key={sku.code} variant="default" padding="sm" style={{ display: 'flex', alignItems: 'center', gap: 12, textAlign: 'start', opacity: isCapped ? 0.7 : 1 }}>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontSize: 14, fontWeight: 700, color: isCapped ? C.textSec : C.text, lineHeight: 1.3 }}>
                            {offer.title}
                          </div>
                          <div style={{ fontSize: 12, color: C.textMuted, marginTop: 3, lineHeight: 1.4 }}>
                            {isCapped ? t('addon_cap_reached_sub', locale) : offer.tag}
                          </div>
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4, flexShrink: 0 }}>
                          {isCapped ? (
                            <Chip tone="surface" size="md">{t('addon_cap_reached', locale)}</Chip>
                          ) : (
                            <>
                              <div style={{ fontSize: 12, fontWeight: 700, color: C.textSec, whiteSpace: 'nowrap' }}>
                                {sku.price} ⭐
                              </div>
                              <Button
                                variant="secondary" size="sm" fullWidth={false}
                                onClick={() => onBuyAddon(sku.code, state?.wishlistId)}
                                disabled={isLoading}
                                loading={addonCheckoutLoading}
                              >
                                {t('addon_cta_buy', locale)}
                              </Button>
                            </>
                          )}
                        </div>
                      </Card>
                    );
                  })}
                </div>
              </div>
            );
          })()}

          {/* ── Footer: primary CTA + "Not now" ghost ──
              NOT position:sticky — sheet manages its own scroll and a
              sticky footer with a transparent gradient was showing
              underlying content bleed-through at the end of scroll. */}
          <div style={{
            marginTop: 22,
            display: 'flex', flexDirection: 'column', gap: 8,
          }}>
            <Button
              variant="primary-gradient" size="lg"
              onClick={() => onUpgrade(selectedPlan)}
              disabled={checkoutLoading || addonCheckoutLoading}
              loading={checkoutLoading}
            >
              {ctaLabel}
            </Button>
            <Button variant="ghost" size="md" onClick={onClose}>
              {t('upsell_not_now', locale)}
            </Button>
          </div>
        </div>
      )}
    </BottomSheet>
  );
}

