  const [wishlistCappedSkus, setWishlistCappedSkus] = useState<Record<string, string[]>>({});
  const [addOns, setAddOns] = useState<AddOnsInfo>({ extraWishlistSlots: 0, extraSubscriptionSlots: 0, seasonalWishlists: [] });
