                    <span style={{ width: 16, height: 16, borderRadius: '50%', background: secretSoft, color: secretColor, display: 'inline-flex', alignItems: 'center', justifyContent: 'center', fontSize: 10, fontWeight: 700, flexShrink: 0 }}>?</span>
